resource.manifest:
apiVersion: v1
kind: Service
metadata:
  name: {{=toJSON(inputs.parameters.proxyName)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: CaptureProxy
      name: {{=toJSON(inputs.parameters.proxyName)}}
      uid: {{=toJSON(inputs.parameters.ownerUid)}}
      controller: true
      blockOwnerDeletion: true
  annotations:
    service.beta.kubernetes.io/aws-load-balancer-type: external
    service.beta.kubernetes.io/aws-load-balancer-nlb-target-type: ip
    service.beta.kubernetes.io/aws-load-balancer-scheme: {{=toJSON(((fromJSON(inputs.parameters.internetFacing)) ? ('internet-facing') : ('internal')))}}
spec:
  type: {{=toJSON(inputs.parameters.serviceType)}}
  selector:
    migrations/proxy: {{=toJSON(inputs.parameters.proxyName)}}
  ports:
    - port: {{inputs.parameters.listenPort}}
      targetPort: {{inputs.parameters.listenPort}}
      protocol: TCP

apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: {{=toJSON(inputs.parameters.proxyName)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: CaptureProxy
      name: {{=toJSON(inputs.parameters.proxyName)}}
      uid: {{=toJSON(inputs.parameters.ownerUid)}}
      controller: true
      blockOwnerDeletion: true
  labels:
    workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
    migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
    migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
spec:
  minAvailable: {{=fromJSON(inputs.parameters.minPodReplicas)}}
  selector:
    matchLabels:
      migrations/proxy: {{=toJSON(inputs.parameters.proxyName)}}

apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{=toJSON(inputs.parameters.proxyName)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: CaptureProxy
      name: {{=toJSON(inputs.parameters.proxyName)}}
      uid: {{=toJSON(inputs.parameters.ownerUid)}}
      controller: true
      blockOwnerDeletion: true
  labels:
    workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
    migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
    migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
spec:
  replicas: {{=fromJSON(inputs.parameters.podReplicas)}}
  minReadySeconds: 2
  strategy:
    type: Recreate
  selector:
    matchLabels:
      migrations/proxy: {{=toJSON(inputs.parameters.proxyName)}}
  template:
    metadata:
      labels:
        migrations/proxy: {{=toJSON(inputs.parameters.proxyName)}}
        workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
        migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
        migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
    spec:
      containers:
        - name: proxy
          image: {{=toJSON(inputs.parameters.imageCaptureProxyLocation)}}
          imagePullPolicy: {{=toJSON(inputs.parameters.imageCaptureProxyPullPolicy)}}
          args:
            - ---INLINE-JSON
            - "{{=toBase64(inputs.parameters.jsonConfig)}}"
          ports:
            - containerPort: {{inputs.parameters.listenPort}}
          resources: {{=fromJSON(inputs.parameters.resources)}}
          readinessProbe:
            tcpSocket:
              port: {{inputs.parameters.listenPort}}
            initialDelaySeconds: 5
            periodSeconds: 5
            timeoutSeconds: 3
            failureThreshold: 3
          env:
            - name: CAPTURE_PROXY_KAFKA_PASSWORD
              valueFrom:
                secretKeyRef:
                  name: {{=toJSON(inputs.parameters.kafkaSecretName)}}
                  key: password
                  optional: {{=!(inputs.parameters.kafkaAuthType == 'scram-sha-512')}}
            - name: CAPTURE_PROXY_SSL_TRUST_CERT_PEM
              value: {{=toJSON(inputs.parameters.sslTrustCertPem)}}
          volumeMounts: {{=sprig.concat([sprig.dict("name", 'kafka-auth-config', "mountPath", '/config/kafka-auth', "readOnly", true), sprig.dict("name", 'kafka-ca', "mountPath", '/config/kafka-ca', "readOnly", true)], fromJSON(inputs.parameters.fileSourceVolumeMounts))}}
      volumes: {{=sprig.concat([sprig.dict("name", 'kafka-auth-config', "configMap", sprig.dict("name", inputs.parameters.kafkaAuthConfigMapName)), sprig.dict("name", 'kafka-ca', "secret", sprig.dict("secretName", inputs.parameters.kafkaCaSecretName, "optional", !(inputs.parameters.kafkaAuthType == 'scram-sha-512')))], fromJSON(inputs.parameters.fileSourceVolumes))}}

apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{=toJSON(inputs.parameters.proxyName)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: CaptureProxy
      name: {{=toJSON(inputs.parameters.proxyName)}}
