  labels:
    workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
    migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
    migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
