  selector:
    matchLabels:
      migrations/proxy: {{=toJSON(inputs.parameters.proxyName)}}
  template:
    metadata:
      labels:
        migrations/proxy: {{=toJSON(inputs.parameters.proxyName)}}
        workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
        migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
        migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
    spec:
      containers:
        - name: proxy
          image: {{=toJSON(inputs.parameters.imageCaptureProxyLocation)}}
          imagePullPolicy: {{=toJSON(inputs.parameters.imageCaptureProxyPullPolicy)}}
          args:
            - ---INLINE-JSON
            - "{{=toBase64(inputs.parameters.jsonConfig)}}"
          ports:
            - containerPort: {{inputs.parameters.listenPort}}
          resources: {{=fromJSON(inputs.parameters.resources)}}
          readinessProbe:
            tcpSocket:
              port: {{inputs.parameters.listenPort}}
            initialDelaySeconds: 5
            periodSeconds: 5
            timeoutSeconds: 3
            failureThreshold: 3
          env:
            - name: CAPTURE_PROXY_KAFKA_PASSWORD
              valueFrom:
                secretKeyRef:
                  name: {{=toJSON(inputs.parameters.kafkaSecretName)}}
                  key: password
                  optional: {{=!(inputs.parameters.kafkaAuthType == 'scram-sha-512')}}
            - name: CAPTURE_PROXY_SSL_TRUST_CERT_PEM
              value: {{=toJSON(inputs.parameters.sslTrustCertPem)}}
          volumeMounts: {{=sprig.concat([sprig.dict("name", 'kafka-auth-config', "mountPath", '/config/kafka-auth', "readOnly", true), sprig.dict("name", 'kafka-ca', "mountPath", '/config/kafka-ca', "readOnly", true), sprig.dict("name", 'tls-certs', "mountPath", '/etc/proxy-tls', "readOnly", true)], fromJSON(inputs.parameters.fileSourceVolumeMounts))}}
      volumes: {{=sprig.concat([sprig.dict("name", 'kafka-auth-config', "configMap", sprig.dict("name", inputs.parameters.kafkaAuthConfigMapName)), sprig.dict("name", 'kafka-ca', "secret", sprig.dict("secretName", inputs.parameters.kafkaCaSecretName, "optional", !(inputs.parameters.kafkaAuthType == 'scram-sha-512'))), sprig.dict("name", 'tls-certs', "secret", sprig.dict("secretName", inputs.parameters.tlsSecretName))], fromJSON(inputs.parameters.fileSourceVolumes))}}

apiVersion: cert-manager.io/v1
kind: Certificate
metadata:
  name: {{=toJSON(inputs.parameters.certName)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: CaptureProxy
      name: {{=toJSON(inputs.parameters.ownerName)}}
      uid: {{=toJSON(inputs.parameters.ownerUid)}}
      controller: true
      blockOwnerDeletion: true
spec:
  secretName: {{=toJSON(inputs.parameters.secretName)}}
  issuerRef:
    name: {{=toJSON(inputs.parameters.issuerName)}}
    kind: {{=toJSON(inputs.parameters.issuerKind)}}
    group: {{=toJSON(inputs.parameters.issuerGroup)}}
  dnsNames: {{inputs.parameters.dnsNames}}
  duration: {{=toJSON(inputs.parameters.duration)}}
  renewBefore: {{=toJSON(inputs.parameters.renewBefore)}}
  privateKey:
    algorithm: RSA
    encoding: PKCS8
    size: 2048
